package com.fasterxml.jackson.databind.type;

import org.junit.runner.RunWith;
import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources",
    glue = {"com.fasterxml.jackson.databind.type.steps"},
    plugin = {"pretty"}
)
public class CucumberTest {

}

package com.fasterxml.jackson.databind.type.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.fasterxml.jackson.databind.type.TypeFactory;

import java.util.Properties;
import java.util.Map;
import java.util.HashMap;

import static org.junit.Assert.*;

public class StepDefs {

    private Object pojo;
    private Properties properties;

    public static class TestPOJO {
        public Integer A;
        public String B;

        public TestPOJO(Integer a, String b) {
            this.A = a;
            this.B = b;
        }
    }

    @Given("a POJO with an Integer field \"A\" having value {int}")
    public void given_a_POJO_with_an_Integer_field_A_having_value(int aValue) {
        // Create a POJO with the specified Integer and String values
        pojo = new TestPOJO(aValue, null);
    }

    @Given("a String field \"B\" having value {string}")
    public void given_a_String_field_B_having_value(String bValue) {
        // Update the B field of the existing POJO
        TestPOJO testPojo = (TestPOJO) pojo;
        testPojo.B = bValue;
        pojo = testPojo;
    }

    @When("the POJO is converted to an instance of \"java.util.Properties\"")
    public void when_the_POJO_is_converted_to_an_instance_of_Properties() {
        try {
            ObjectMapper mapper = new ObjectMapper();
            // This conversion should handle non-String values appropriately
            properties = mapper.convertValue(pojo, Properties.class);
        } catch (Exception e) {
            // Capture the exception if conversion fails
            e.printStackTrace();
        }
    }

    @Then("the \"Properties\" instance should contain key \"A\" with String value {string}")
    public void then_the_Properties_instance_should_contain_key_A_with_String_value(String expectedValue) {
        assertNotNull("Properties should not be null", properties);
        assertEquals("Value for key A should match", expectedValue, properties.getProperty("A"));
    }

    @Then("the \"Properties\" instance should contain key \"B\" with String value {string}")
    public void then_the_Properties_instance_should_contain_key_B_with_String_value(String expectedValue) {
        assertNotNull("Properties should not be null", properties);
        assertEquals("Value for key B should match", expectedValue, properties.getProperty("B"));
    }

    @Then("calling \"getProperty\" on the Properties instance with key \"A\" should return {string}")
    public void then_calling_getProperty_on_the_Properties_instance_with_key_A_should_return(String expectedValue) {
        assertNotNull("Properties should not be null", properties);
        String actualValue = properties.getProperty("A");
        assertEquals("getProperty with key A should return expected value", expectedValue, actualValue);
    }
}

package com.fasterxml.jackson.databind.deser.std;

import java.nio.ByteBuffer;
import java.util.*;
import java.util.concurrent.atomic.AtomicBoolean;

import com.fasterxml.jackson.databind.*;

/**
 * Container class that contains serializers for JDK types that
 * require special handling for some reason.
 */
public class JdkDeserializers
{
    private final static HashSet<String> _classNames = new HashSet<String>();
    static {
        // note: can skip primitive types; other ways to check them:
        Class<?>[] types = new Class<?>[] {
                UUID.class,
                AtomicBoolean.class,
                StackTraceElement.class,
                ByteBuffer.class
        };
        for (Class<?> cls : types) { _classNames.add(cls.getName()); }
        for (Class<?> cls : FromStringDeserializer.types()) { _classNames.add(cls.getName()); }
    }

    public static JsonDeserializer<?> find(Class<?> rawType, String clsName)
    {
        if (_classNames.contains(clsName)) {
            JsonDeserializer<?> d = FromStringDeserializer.findDeserializer(rawType);
            if (d != null) {
                return d;
            }
            if (rawType == UUID.class) {
                return new UUIDDeserializer();
            }
            if (rawType == StackTraceElement.class) {
                return new StackTraceElementDeserializer();
            }
            if (rawType == AtomicBoolean.class) {
                // (note: AtomicInteger/Long work due to single-arg constructor. For now?
                return new AtomicBooleanDeserializer();
            }
            if (rawType == ByteBuffer.class) {
                return new ByteBufferDeserializer();
            }
        }
        return null;
    }
}

package com.fasterxml.jackson.databind.convert;

import java.util.*;

import com.fasterxml.jackson.core.type.TypeReference;
import com.fasterxml.jackson.databind.*;
import com.fasterxml.jackson.databind.annotation.JsonSerialize;
import com.fasterxml.jackson.databind.util.StdConverter;

public class TestMapConversions
    extends com.fasterxml.jackson.databind.BaseMapTest
{
    final ObjectMapper MAPPER = new ObjectMapper();

    enum AB { A, B; }

    static class Bean {
        public Integer A;
        public String B;
    }

    // [Issue#287]

    @JsonSerialize(converter=RequestConverter.class)
    static class Request {
        public int x() {
            return 1;
        }
    }

    static class RequestConverter extends StdConverter<Request, Map<String,Object>> {
        @Override
        public Map<String,Object> convert(final Request value) {
            final Map<String, Object> test = new LinkedHashMap<String, Object>();
            final Map<String, Object> innerTest = new LinkedHashMap<String, Object>();
            innerTest.put("value", value.x());
            test.put("hello", innerTest);
            return test;
        }
    }

    /*
    /**********************************************************
    /* Test methods
    /**********************************************************
     */

    /**
     * Test that verifies that we can go between couple of types of Maps...
     */
    public void testMapToMap()
    {
        Map<String,Integer> input = new LinkedHashMap<String,Integer>();
        input.put("A", Integer.valueOf(3));
        input.put("B", Integer.valueOf(-4));
        Map<AB,String> output = MAPPER.convertValue(input,
                new TypeReference<Map<AB,String>>() { });
        assertEquals(2, output.size());
        assertEquals("3", output.get(AB.A));
        assertEquals("-4", output.get(AB.B));

        // Let's try the other way too... and mix up types a bit
        Map<String,Integer> roundtrip = MAPPER.convertValue(input,
                new TypeReference<TreeMap<String,Integer>>() { });
        assertEquals(2, roundtrip.size());
        assertEquals(Integer.valueOf(3), roundtrip.get("A"));
        assertEquals(Integer.valueOf(-4), roundtrip.get("B"));
    }

    public void testMapToBean()
    {
        EnumMap<AB,String> map = new EnumMap<AB,String>(AB.class);
        map.put(AB.A, "   17");
        map.put(AB.B, " -1");
        Bean bean = MAPPER.convertValue(map, Bean.class);
        assertEquals(Integer.valueOf(17), bean.A);
        assertEquals(" -1", bean.B);
    }

    public void testBeanToMap()
    {
        Bean bean = new Bean();
        bean.A = 129;
        bean.B = "13";
        EnumMap<AB,String> result = MAPPER.convertValue(bean,
                new TypeReference<EnumMap<AB,String>>() { });
        assertEquals("129", result.get(AB.A));
        assertEquals("13", result.get(AB.B));
    }

    // [Issue#287]: Odd problems with `Object` type, static typing
    public void testIssue287() throws Exception
    {
        // use local instance to ensure no caching affects it:
        final ObjectMapper mapper = new ObjectMapper();
        final Request request = new Request();
        final String retString = mapper.writeValueAsString(request);
        assertEquals("{\"hello\":{\"value\":1}}",retString);
    }

    // [databind#810]
    public void testMapToProperties() throws Exception
    {
        Bean bean = new Bean();
        bean.A = 129;
        bean.B = "13";
        Properties props = MAPPER.convertValue(bean, Properties.class);

        assertEquals(2, props.size());

        assertEquals("13", props.getProperty("B"));
        // should coercce non-Strings to Strings
        assertEquals("129", props.getProperty("A"));
    }
}

